/**
 * Aura Validators
 *
 * Zod schemas for validating portfolio data structures.
 * These schemas ensure type safety and provide helpful error messages.
 */

import { z } from 'zod';

/**
 * Schema for validating a single prompt
 */
export const promptSchema = z.object({
  id: z.string().uuid('Prompt ID must be a valid UUID'),
  content: z.string().min(1, 'Prompt content cannot be empty'),
  response: z.string().min(1, 'Response content cannot be empty'),
  timestamp: z.string().datetime('Timestamp must be a valid ISO datetime'),
  title: z.string().optional(),
  metadata: z
    .object({
      model: z.string().optional(),
      tokens: z.number().optional(),
      duration: z.number().optional(),
    })
    .optional(),
});

/**
 * Schema for validating OG image metadata
 */
export const ogImageMetadataSchema = z.object({
  path: z.string(),
  width: z.number().positive(),
  height: z.number().positive(),
  alt: z.string(),
});

/**
 * Schema for validating a portfolio
 */
export const portfolioSchema = z.object({
  id: z.string().uuid('Portfolio ID must be a valid UUID'),
  title: z.string().min(1, 'Portfolio title cannot be empty'),
  prompts: z.array(promptSchema).min(1, 'Portfolio must have at least one prompt'),
  createdAt: z.string().datetime('Creation timestamp must be a valid ISO datetime'),
  ogImage: ogImageMetadataSchema.optional(),
});

/**
 * Schema for validating Claude conversation turns
 */
export const claudeTurnSchema = z.object({
  role: z.enum(['human', 'assistant'], {
    errorMap: () => ({ message: 'Role must be either "human" or "assistant"' }),
  }),
  content: z.string().min(1, 'Message content cannot be empty'),
  timestamp: z.string().datetime().optional(),
  metadata: z
    .object({
      model: z.string().optional(),
      tokens: z.number().optional(),
    })
    .optional(),
});

/**
 * Schema for validating Claude export format
 */
export const claudeExportSchema = z.object({
  version: z.string().optional(),
  exportedAt: z.string().datetime().optional(),
  title: z.string().optional(),
  conversation: z.array(claudeTurnSchema).min(1, 'Export must contain at least one message'),
  metadata: z
    .object({
      model: z.string().optional(),
      totalTokens: z.number().optional(),
    })
    .optional(),
});

/**
 * Type inference from schemas
 */
export type PromptInput = z.infer<typeof promptSchema>;
export type PortfolioInput = z.infer<typeof portfolioSchema>;
export type ClaudeTurnInput = z.infer<typeof claudeTurnSchema>;
export type ClaudeExportInput = z.infer<typeof claudeExportSchema>;

/**
 * Validation helper for portfolios
 */
export function validatePortfolio(data: unknown): { valid: boolean; error?: string } {
  const result = portfolioSchema.safeParse(data);
  if (!result.success) {
    return {
      valid: false,
      error: result.error.errors.map((e) => e.message).join(', '),
    };
  }
  return { valid: true };
}

/**
 * Validation helper for Claude exports
 */
export function validateClaudeExport(data: unknown): { valid: boolean; error?: string } {
  const result = claudeExportSchema.safeParse(data);
  if (!result.success) {
    return {
      valid: false,
      error: result.error.errors.map((e) => e.message).join(', '),
    };
  }
  return { valid: true };
}

/**
 * Claude Parser
 *
 * Parses Claude conversation export JSON into structured Portfolio objects.
 * Wrapped in try/catch with graceful error handling for schema drift.
 */

import type {
  ClaudeExport,
  ClaudeConversationTurn,
  Portfolio,
  Prompt,
  ParseResult,
} from '@/types/aura';
import { validateClaudeExport } from './validators';

/**
 * Generates a UUID v4
 */
function generateUUID(): string {
  if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) {
    return crypto.randomUUID();
  }
  // Fallback for environments without crypto.randomUUID
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

/**
 * Extracts a title from prompt content
 * Takes first ~60 characters or first line, whichever is shorter
 */
function extractTitle(content: string): string {
  const firstLine = content.split('\n')[0]?.trim();
  if (firstLine && firstLine.length <= 60) {
    return firstLine.replace(/[#*`]/g, '').trim();
  }
  return content.slice(0, 60).replace(/[#*`]/g, '').trim() + '...';
}

/**
 * Pairs human prompts with assistant responses
 */
function pairConversation(turns: ClaudeConversationTurn[]): Prompt[] {
  const prompts: Prompt[] = [];
  let currentHumanTurn: ClaudeConversationTurn | null = null;

  for (const turn of turns) {
    if (turn.role === 'human') {
      // If we have a pending human turn without a response, pair it anyway
      if (currentHumanTurn) {
        prompts.push({
          id: generateUUID(),
          content: currentHumanTurn.content,
          response: '[No response in export]',
          timestamp: currentHumanTurn.timestamp || new Date().toISOString(),
          title: extractTitle(currentHumanTurn.content),
          metadata: currentHumanTurn.metadata,
        });
      }
      currentHumanTurn = turn;
    } else if (turn.role === 'assistant' && currentHumanTurn) {
      // Pair this response with the previous human turn
      prompts.push({
        id: generateUUID(),
        content: currentHumanTurn.content,
        response: turn.content,
        timestamp: currentHumanTurn.timestamp || turn.timestamp || new Date().toISOString(),
        title: extractTitle(currentHumanTurn.content),
        metadata: {
          ...currentHumanTurn.metadata,
          ...turn.metadata,
        },
      });
      currentHumanTurn = null;
    }
  }

  // Handle any remaining human turn without a response
  if (currentHumanTurn) {
    prompts.push({
      id: generateUUID(),
      content: currentHumanTurn.content,
      response: '[No response in export]',
      timestamp: currentHumanTurn.timestamp || new Date().toISOString(),
      title: extractTitle(currentHumanTurn.content),
      metadata: currentHumanTurn.metadata,
    });
  }

  return prompts;
}

/**
 * Parses a Claude export JSON into a Portfolio
 */
export function parseClaudeExport(jsonData: unknown): ParseResult {
  try {
    // First, try to parse as string if it's a string
    let data: unknown = jsonData;
    if (typeof jsonData === 'string') {
      try {
        data = JSON.parse(jsonData);
      } catch (parseError) {
        return {
          success: false,
          error: 'Invalid JSON format. Please ensure you uploaded a valid Claude export file.',
          errorDetails: parseError,
        };
      }
    }

    // Validate the structure
    const validation = validateClaudeExport(data);
    if (!validation.valid) {
      return {
        success: false,
        error: `Invalid Claude export format: ${validation.error}`,
      };
    }

    const claudeExport = data as ClaudeExport;

    // Check for conversation array
    if (!Array.isArray(claudeExport.conversation)) {
      return {
        success: false,
        error:
          'This export format is not recognized. Please check you exported from Claude\'s Settings → Data → Export.',
      };
    }

    // Pair the conversation turns
    const prompts = pairConversation(claudeExport.conversation);

    if (prompts.length === 0) {
      return {
        success: false,
        error: 'No prompts found in this export. The conversation may be empty.',
      };
    }

    // Generate the portfolio
    const portfolio: Portfolio = {
      id: generateUUID(),
      title: claudeExport.title || extractTitle(prompts[0].content),
      prompts,
      createdAt: claudeExport.exportedAt || new Date().toISOString(),
    };

    return {
      success: true,
      portfolio,
    };
  } catch (error) {
    return {
      success: false,
      error:
        'This export format is not recognized. Please check you exported from Claude\'s Settings → Data → Export.',
      errorDetails: error,
    };
  }
}

/**
 * Validates if a file appears to be a Claude export
 * Quick check before full parsing
 */
export function isLikelyClaudeExport(data: unknown): boolean {
  if (!data || typeof data !== 'object') {
    return false;
  }

  const obj = data as Record<string, unknown>;

  // Check for conversation array (required)
  if (!Array.isArray(obj.conversation)) {
    return false;
  }

  // Check for typical Claude export structure
  const hasConversation = obj.conversation.length > 0;
  const firstTurn = obj.conversation[0] as Record<string, unknown>;

  return hasConversation && firstTurn && typeof firstTurn.role === 'string';
}

/**
 * Markdown Renderer
 *
 * Renders markdown content with gallery-grade typography and syntax highlighting.
 * Simple, dependency-free implementation for static generation.
 */

/**
 * Escapes HTML special characters
 */
function escapeHtml(text: string): string {
  const htmlEntities: Record<string, string> = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;',
  };
  return text.replace(/[&<>"']/g, (char) => htmlEntities[char]);
}

/**
 * Simple syntax highlighting for code blocks
 * Applies basic colorization to common patterns
 */
function highlightCode(code: string, language?: string): string {
  // Escape HTML first
  let highlighted = escapeHtml(code);

  // Common patterns for syntax highlighting
  const patterns: { regex: RegExp; className: string }[] = [
    // Strings
    { regex: /(&quot;.*?&quot;|&#39;.*?&#39;)/g, className: 'text-green-400' },
    // Keywords
    {
      regex:
        /\b(const|let|var|function|return|if|else|for|while|class|import|export|from|async|await|try|catch|throw|new|this|typeof|instanceof)\b/g,
      className: 'text-purple-400',
    },
    // Numbers
    { regex: /\b(\d+\.?\d*)\b/g, className: 'text-orange-400' },
    // Comments
    { regex: /(\/\/.*$|\/\*[\s\S]*?\*\/)/gm, className: 'text-gray-500' },
    // Function calls
    { regex: /\b([a-zA-Z_][a-zA-Z0-9_]*)\s*\(/g, className: 'text-blue-400' },
  ];

  // Apply patterns (order matters - strings first to avoid highlighting inside them)
  for (const { regex, className } of patterns) {
    highlighted = highlighted.replace(regex, (match) => {
      // Don't double-wrap already highlighted content
      if (match.includes('class=')) {
        return match;
      }
      return `<span class="${className}">${match}</span>`;
    });
  }

  return highlighted;
}

/**
 * Parses inline markdown (bold, italic, code, links)
 */
function parseInline(text: string): string {
  let result = escapeHtml(text);

  // Inline code (must be before bold/italic to avoid conflicts)
  result = result.replace(/`([^`]+)`/g, '<code class="bg-surface-elevated px-1.5 py-0.5 rounded text-sm font-mono text-text-primary">$1</code>');

  // Bold
  result = result.replace(/\*\*([^*]+)\*\*/g, '<strong class="font-semibold">$1</strong>');

  // Italic
  result = result.replace(/\*([^*]+)\*/g, '<em class="italic">$1</em>');

  // Links
  result = result.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" class="text-accent-primary hover:text-accent-secondary underline underline-offset-2" target="_blank" rel="noopener noreferrer">$1</a>',
  );

  return result;
}

/**
 * Renders markdown to HTML with gallery-grade typography
 */
export function renderMarkdown(content: string): string {
  const lines = content.split('\n');
  const blocks: string[] = [];
  let inCodeBlock = false;
  let codeBlockContent: string[] = [];
  let codeBlockLanguage = '';

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]!;

    // Code block handling
    if (line.startsWith('```')) {
      if (!inCodeBlock) {
        // Start of code block
        inCodeBlock = true;
        codeBlockLanguage = line.slice(3).trim();
        codeBlockContent = [];
      } else {
        // End of code block
        inCodeBlock = false;
        const highlighted = highlightCode(codeBlockContent.join('\n'), codeBlockLanguage);
        blocks.push(
          `<pre class="bg-surface-elevated rounded-lg p-4 overflow-x-auto my-4 border border-border-subtle"><code class="font-mono text-sm leading-relaxed">${highlighted}</code></pre>`,
        );
      }
      continue;
    }

    if (inCodeBlock) {
      codeBlockContent.push(line);
      continue;
    }

    // Headers
    if (line.startsWith('### ')) {
      blocks.push(`<h3 class="text-xl font-semibold mt-6 mb-3 text-text-primary">${parseInline(line.slice(4))}</h3>`);
      continue;
    }
    if (line.startsWith('## ')) {
      blocks.push(`<h2 class="text-2xl font-semibold mt-8 mb-4 text-text-primary">${parseInline(line.slice(3))}</h2>`);
      continue;
    }
    if (line.startsWith('# ')) {
      blocks.push(`<h1 class="text-3xl font-bold mt-8 mb-4 text-text-primary">${parseInline(line.slice(2))}</h1>`);
      continue;
    }

    // Blockquotes
    if (line.startsWith('> ')) {
      blocks.push(
        `<blockquote class="border-l-4 border-accent-primary pl-4 my-4 text-text-secondary italic">${parseInline(line.slice(2))}</blockquote>`,
      );
      continue;
    }

    // Unordered lists
    if (line.match(/^[-*]\s+/)) {
      blocks.push(`<li class="ml-4 my-1 text-text-primary">${parseInline(line.replace(/^[-*]\s+/, ''))}</li>`);
      continue;
    }

    // Ordered lists
    if (line.match(/^\d+\.\s+/)) {
      blocks.push(`<li class="ml-4 my-1 text-text-primary">${parseInline(line.replace(/^\d+\.\s+/, ''))}</li>`);
      continue;
    }

    // Empty lines
    if (line.trim() === '') {
      blocks.push('<br/>');
      continue;
    }

    // Regular paragraphs
    blocks.push(`<p class="my-3 text-text-primary leading-relaxed">${parseInline(line)}</p>`);
  }

  return blocks.join('\n');
}

/**
 * Renders plain text with minimal formatting (for prompts without markdown)
 */
export function renderPlainText(content: string): string {
  return `<p class="my-3 text-text-primary leading-relaxed">${escapeHtml(content)}</p>`;
}

/**
 * Detects if content contains markdown syntax
 */
export function isMarkdown(content: string): boolean {
  const markdownPatterns = [
    /^#{1,6}\s+/m, // Headers
    /\*\*[^*]+\*\*/, // Bold
    /\*[^*]+\*/, // Italic
    /`[^`]+`/, // Inline code
    /^```/m, // Code blocks
    /^\[.+\]\(.+\)/m, // Links
    /^[-*]\s+/m, // Unordered lists
    /^\d+\.\s+/m, // Ordered lists
    /^>\s+/m, // Blockquotes
  ];

  return markdownPatterns.some((pattern) => pattern.test(content));
}

