/**
 * PromptCard Component
 *
 * Displays a single prompt with its response in the gallery template.
 * Hero prompt display with large typography and elegant code blocks.
 */

'use client';

import { renderMarkdown, isMarkdown } from '@/lib/markdownRenderer';
import type { Prompt } from '@/types/aura';

interface PromptCardProps {
  prompt: Prompt;
}

/**
 * Formats a date string for display
 */
function formatDate(dateString: string): string {
  try {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  } catch {
    return dateString;
  }
}

/**
 * PromptCard Component
 */
export function PromptCard({ prompt }: PromptCardProps) {
  const contentIsMarkdown = isMarkdown(prompt.content);
  const responseIsMarkdown = isMarkdown(prompt.response);

  return (
    <article className="prompt-card bg-surface rounded-2xl p-8 mb-8 border border-border-subtle">
      <header className="mb-6">
        {prompt.title && (
          <h2 className="text-2xl font-bold text-text-primary mb-2">{prompt.title}</h2>
        )}
        <time className="text-sm text-text-muted">{formatDate(prompt.timestamp)}</time>
      </header>

      <section className="prompt-content mb-6">
        <h3 className="text-sm font-semibold text-text-secondary uppercase tracking-wider mb-3">
          Prompt
        </h3>
        <div className="prose prose-invert max-w-none">
          {contentIsMarkdown ? (
            <div
              className="text-text-primary leading-relaxed"
              dangerouslySetInnerHTML={{ __html: renderMarkdown(prompt.content) }}
            />
          ) : (
            <p className="text-text-primary leading-relaxed">{prompt.content}</p>
          )}
        </div>
      </section>

      <section className="response-content">
        <h3 className="text-sm font-semibold text-text-secondary uppercase tracking-wider mb-3">
          Response
        </h3>
        <div className="prose prose-invert max-w-none bg-surface-elevated rounded-xl p-6 border border-border-subtle">
          {responseIsMarkdown ? (
            <div
              className="text-text-primary leading-relaxed"
              dangerouslySetInnerHTML={{ __html: renderMarkdown(prompt.response) }}
            />
          ) : (
            <p className="text-text-primary leading-relaxed">{prompt.response}</p>
          )}
        </div>
      </section>
    </article>
  );
}

/**
 * Template Component
 *
 * The one sacred template for Aura portfolios.
 * Dark mode, midnight spotlight aesthetic, gallery-grade typography.
 * No theming, no configuration - one beautiful layout.
 */

import type { Portfolio } from '@/types/aura';
import { PromptCard } from './PromptCard';

interface TemplateProps {
  portfolio: Portfolio;
}

/**
 * Formats a date string for display
 */
function formatDate(dateString: string): string {
  try {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    });
  } catch {
    return dateString;
  }
}

/**
 * Shares the portfolio using the Web Share API
 */
async function sharePortfolio(title: string) {
  if (typeof navigator !== 'undefined' && navigator.share) {
    try {
      await navigator.share({
        title: `${title} — Aura Portfolio`,
        text: 'Check out this AI prompt portfolio',
        url: window.location.href,
      });
    } catch {
      // Share cancelled or not supported
    }
  }
}

/**
 * Copies the portfolio URL to clipboard
 */
async function copyLink() {
  if (typeof navigator !== 'undefined' && navigator.clipboard) {
    try {
      await navigator.clipboard.writeText(window.location.href);
      alert('Link copied to clipboard!');
    } catch {
      alert('Failed to copy link');
    }
  }
}

/**
 * The Sacred Template Component
 *
 * A single, opinionated layout for all portfolios.
 * Dark mode only. No configuration. No alternatives.
 */
export function Template({ portfolio }: TemplateProps) {
  return (
    <main className="container mx-auto max-w-3xl px-6 py-16 md:py-24">
      {/* Header */}
      <header className="mb-16 pb-8 border-b border-border-subtle">
        <h1 className="text-4xl md:text-5xl font-bold text-text-primary mb-3 tracking-tight">
          {portfolio.title}
        </h1>
        <p className="text-text-muted text-sm">
          Generated on {formatDate(portfolio.createdAt)}
        </p>
