          <span className="text-text-muted text-sm ml-auto">
            Generated with Aura
          </span>
        </div>
      </footer>
    </main>
  );
}

/**
 * UploadDropzone Component
 *
 * Claude JSON drag-and-drop upload with validation and progress state.
 * Single, obvious upload action - no wizard, no multi-step flow.
 */

'use client';

import { useCallback, useState, useRef } from 'react';
import { parseClaudeExport } from '@/lib/claudeParser';
import type { Portfolio, ParseResult } from '@/types/aura';

interface UploadDropzoneProps {
  onUploadSuccess: (portfolio: Portfolio) => void;
  onUploadError: (error: string) => void;
}

type UploadState = 'idle' | 'dragging' | 'processing' | 'error' | 'success';

/**
 * UploadDropzone Component
 *
 * A single, obvious file drop-zone for Claude JSON exports.
 * Handles drag-and-drop, file selection, parsing, and error states.
 */
export function UploadDropzone({ onUploadSuccess, onUploadError }: UploadDropzoneProps) {
  const [state, setState] = useState<UploadState>('idle');
  const [errorMessage, setErrorMessage] = useState<string>('');
  const [fileName, setFileName] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  /**
   * Processes an uploaded file
   */
  const processFile = useCallback(async (file: File) => {
    setState('processing');
    setFileName(file.name);

    try {
      // Validate file type
      if (!file.name.toLowerCase().endsWith('.json')) {
        throw new Error('Please upload a JSON file exported from Claude.');
      }

      // Validate file size (50MB max)
      const maxSize = 50 * 1024 * 1024;
      if (file.size > maxSize) {
        throw new Error('File is too large. Please upload a file under 50MB.');
      }

      // Read file contents
      const text = await file.text();

      // Parse the Claude export
      const result: ParseResult = parseClaudeExport(text);

      if (!result.success || !result.portfolio) {
        throw new Error(
          result.error || 'Failed to parse Claude export. Please check the file format.',
        );
      }

      // Success
      setState('success');
      onUploadSuccess(result.portfolio);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'An unexpected error occurred';
      setState('error');
      setErrorMessage(message);
      onUploadError(message);
    }
  }, [onUploadSuccess, onUploadError]);

  /**
   * Handles file input change
   */
  const handleFileInput = useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
        processFile(file);
      }
    },
    [processFile],
  );

  /**
   * Handles drag enter
   */
  const handleDragEnter = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.stopPropagation();
    setState('dragging');
  }, []);

  /**
   * Handles drag leave
   */
  const handleDragLeave = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.stopPropagation();
    setState('idle');
  }, []);

  /**
   * Handles drag over
   */
  const handleDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.stopPropagation();
  }, []);

  /**
   * Handles drop
   */
  const handleDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      event.stopPropagation();
      setState('idle');

      const file = event.dataTransfer.files?.[0];
      if (file) {
        processFile(file);
      }
    },
    [processFile],
  );

  /**
   * Triggers file input click
   */
  const handleClick = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  /**
   * Resets the upload state
   */
  const handleReset = useCallback(() => {
    setState('idle');
    setErrorMessage('');
    setFileName('');
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  }, []);

  return (
    <div className="w-full">
      {/* Drop Zone */}
      <div
        onClick={handleClick}
        onDragEnter={handleDragEnter}
        onDragLeave={handleDragLeave}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
        className={`
          relative w-full min-h-[280px] rounded-2xl border-2 border-dashed
          transition-all duration-200 cursor-pointer
          flex flex-col items-center justify-center
          ${state === 'dragging'
            ? 'border-accent-primary bg-surface-elevated scale-[1.02]'
            : 'border-border-subtle bg-surface hover:border-accent-primary/50 hover:bg-surface-elevated/50'
          }
          ${state === 'processing' ? 'opacity-50 pointer-events-none' : ''}
          ${state === 'error' ? 'border-red-500/50 bg-red-500/5' : ''}
          ${state === 'success' ? 'border-green-500/50 bg-green-500/5' : ''}
        `}
      >
        {/* Hidden file input */}
        <input
          ref={fileInputRef}
          type="file"
          accept=".json"
          onChange={handleFileInput}
          className="hidden"
        />

        {/* Content based on state */}
        {state === 'processing' ? (
          <div className="text-center">
            <div className="w-12 h-12 border-4 border-accent-primary border-t-transparent rounded-full animate-spin mx-auto mb-4" />
            <p className="text-text-primary font-medium">Processing your export...</p>
            {fileName && <p className="text-text-muted text-sm mt-2">{fileName}</p>}
          </div>
        ) : state === 'error' ? (
          <div className="text-center px-8">
            <div className="w-12 h-12 rounded-full bg-red-500/20 flex items-center justify-center mx-auto mb-4">
              <svg
                className="w-6 h-6 text-red-400"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </div>
            <p className="text-red-400 font-medium">{errorMessage}</p>
            <button
              onClick={(e) => {
                e.stopPropagation();
                handleReset();
              }}
              className="mt-4 text-accent-primary hover:text-accent-secondary text-sm underline underline-offset-2"
            >
              Try again
            </button>
          </div>
        ) : state === 'success' ? (
          <div className="text-center px-8">
            <div className="w-12 h-12 rounded-full bg-green-500/20 flex items-center justify-center mx-auto mb-4">
              <svg
                className="w-6 h-6 text-green-400"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M5 13l4 4L19 7"
                />
              </svg>
            </div>
            <p className="text-green-400 font-medium">Portfolio generated successfully!</p>
            <p className="text-text-muted text-sm mt-2">Redirecting to your portfolio...</p>
          </div>
        ) : (
          <div className="text-center px-8">
            <div className="w-16 h-16 rounded-2xl bg-surface-elevated flex items-center justify-center mx-auto mb-6">
              <svg
                className="w-8 h-8 text-accent-primary"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1.5}
                  d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
                />
              </svg>
            </div>
            <p className="text-text-primary font-medium text-lg mb-2">
              Drop your Claude export here
            </p>
            <p className="text-text-muted text-sm mb-4">
              or click to browse
            </p>
            <p className="text-text-muted text-xs">
              Claude → Settings → Data → Export
            </p>
          </div>
        )}
      </div>

      {/* Helper text */}
      {state !== 'processing' && state !== 'success' && (
        <p className="text-center text-text-muted text-xs mt-4">
          Supports Claude conversation exports (.json files)
        </p>
      )}
    </div>
  );
}

